<script>
(function () {
  const slider = document.getElementById('logoSlider1');
  const track  = document.getElementById('logoTrack1');

  // Duplicate logos until the track is at least 2x the container width
  function duplicateLogos() {
    const containerWidth = slider.clientWidth;
    const logos = Array.from(track.children);
    let attempts = 0;

    while (track.scrollWidth < containerWidth * 2 && attempts < 10) {
      logos.forEach(logo => track.appendChild(logo.cloneNode(true)));
      attempts++;
    }
  }

  window.addEventListener('load', duplicateLogos);
})();
